"""Redis client configuration for HealthBridge patient portal.

Provides a singleton Redis connection pool for session storage,
caching, and rate limiting across the application.
"""

import redis
from typing import Optional
from infra.config import settings


class RedisClient:
    """Managed Redis client with connection pooling."""

    _instance: Optional['RedisClient'] = None
    _pool: Optional[redis.ConnectionPool] = None

    def __new__(cls) -> 'RedisClient':
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._pool = redis.ConnectionPool(
                host=settings.REDIS_HOST,
                port=settings.REDIS_PORT,
                db=settings.REDIS_DB,
                password=settings.REDIS_PASSWORD,
                decode_responses=True,
                max_connections=settings.REDIS_MAX_CONNECTIONS,
            )
        return cls._instance

    @property
    def conn(self) -> redis.Redis:
        """Get a Redis connection from the pool."""
        return redis.Redis(connection_pool=self._pool)

    def health_check(self) -> bool:
        """Verify Redis connectivity."""
        try:
            return self.conn.ping()
        except redis.ConnectionError:
            return False


def get_redis() -> redis.Redis:
    """Convenience function to get a Redis connection."""
    return RedisClient().conn
